mapper.select:
select 
from meeting_room


        and building_id = #{buildingId}


        and floor = #{floor}


        and capacity >= #{capacity}


        and status = #{status}


        and (
            lower(name) like concat('%', lower(#{keyword}), '%')
            or lower(ifnull(floor, '')) like concat('%', lower(#{keyword}), '%')
            or lower(ifnull(remark, '')) like concat('%', lower(#{keyword}), '%')
        )


order by building_id asc, floor asc, name asc

select 
from meeting_room r
where r.status = 'ENABLED'

    and r.building_id = #{buildingId}


    and r.capacity >= #{capacity}

  and not exists (
        select 1 from booking b
        where b.room_id = r.id
          and b.status <> 'CANCELED'
          and b.approval_status <> 'REJECTED'
          and b.start_time_ms < #{endTimeMs}
          and b.end_time_ms > #{startTimeMs}
  )
order by r.building_id asc, r.floor asc, r.name asc
